import React from 'react';

const Dashboard = ({ data, onReset }) => {
    return (
        <div>
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'baseline'}}>
                <h2>Analysis Results</h2>
                <button onClick={onReset} style={{background: 'none', border: 'none', cursor: 'pointer', textDecoration: 'underline'}}>Upload New File</button>
            </div>
            
            <div style={{display: 'grid', gap: '20px', marginTop: '20px'}}>
                {data.map((item, index) => (
                    <div key={index} style={{border: '1px solid #eee', padding: '20px', borderRadius: '12px', borderLeft: '5px solid #38a169'}}>
                        <div style={{display: 'flex', justifyContent: 'space-between'}}>
                            <strong style={{fontSize: '1.2rem'}}>{item.gene} ({item.rsid})</strong>
                            <span style={{background: '#f0f0f0', padding: '2px 8px', borderRadius: '4px'}}>{item.genotype}</span>
                        </div>
                        <p style={{margin: '10px 0', color: '#444'}}><strong>Trait:</strong> {item.trait}</p>
                        <div style={{background: '#f0fff4', padding: '15px', borderRadius: '8px', border: '1px solid #c6f6d5'}}>
                            <strong>Recommendation:</strong>
                            <p style={{margin: '5px 0'}}>{item.recommendation}</p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default Dashboard;
